61	const DiffPanelInlineSidebar = (props: {
62	  diffOpen: boolean;
63	  onCloseDiff: () => void;
64	  onOpenDiff: () => void;
65	}) => {
66	  const { diffOpen, onCloseDiff, onOpenDiff } = props;
67	  const onOpenChange = useCallback(
68	    (open: boolean) => {
69	      if (open) {
70	        onOpenDiff();
71	        return;
72	      }
73	      onCloseDiff();
74	    },
75	    [onCloseDiff, onOpenDiff],
76	  );
77	  const shouldAcceptInlineSidebarWidth = useCallback(
78	    ({ nextWidth, wrapper }: { nextWidth: number; wrapper: HTMLElement }) => {
79	      const composerForm = document.querySelector<HTMLElement>("[data-chat-composer-form='true']");
80	      if (!composerForm) return true;
81	      const composerViewport = composerForm.parentElement;
82	      if (!composerViewport) return true;
83	      const previousSidebarWidth = wrapper.style.getPropertyValue("--sidebar-width");
84	      wrapper.style.setProperty("--sidebar-width", `${nextWidth}px`);
85	
86	      const viewportStyle = window.getComputedStyle(composerViewport);
87	      const viewportPaddingLeft = Number.parseFloat(viewportStyle.paddingLeft) || 0;
88	      const viewportPaddingRight = Number.parseFloat(viewportStyle.paddingRight) || 0;
89	      const viewportContentWidth = Math.max(
90	        0,
91	        composerViewport.clientWidth - viewportPaddingLeft - viewportPaddingRight,
92	      );
93	      const formRect = composerForm.getBoundingClientRect();
94	      const hasComposerOverflow = composerForm.scrollWidth > composerForm.clientWidth + 0.5;
95	      const overflowsViewport = formRect.width > viewportContentWidth + 0.5;
96	
97	      if (previousSidebarWidth.length > 0) {
98	        wrapper.style.setProperty("--sidebar-width", previousSidebarWidth);
99	      } else {
100	        wrapper.style.removeProperty("--sidebar-width");
101	      }
102	
103	      return !hasComposerOverflow && !overflowsViewport;
104	    },
105	    [],
106	  );
