135	function ChatThreadRouteView() {
136	  const threadsHydrated = useStore((store) => store.threadsHydrated);
137	  const navigate = useNavigate();
138	  const threadId = Route.useParams({
139	    select: (params) => ThreadId.makeUnsafe(params.threadId),
140	  });
141	  const search = Route.useSearch();
142	  const threadExists = useStore((store) => store.threads.some((thread) => thread.id === threadId));
143	  const draftThreadExists = useComposerDraftStore(
144	    (store) => Object.hasOwn(store.draftThreadsByThreadId, threadId),
145	  );
146	  const routeThreadExists = threadExists || draftThreadExists;
147	  const diffOpen = search.diff === "1";
148	  const shouldUseDiffSheet = useMediaQuery(DIFF_INLINE_LAYOUT_MEDIA_QUERY);
149	  const closeDiff = useCallback(() => {
150	    void navigate({
151	      to: "/$threadId",
152	      params: { threadId },
153	      search: (previous) => {
154	        return stripDiffSearchParams(previous);
155	      },
156	    });
157	  }, [navigate, threadId]);
158	  const openDiff = useCallback(() => {
159	    void navigate({
160	      to: "/$threadId",
161	      params: { threadId },
162	      search: (previous) => {
163	        const rest = stripDiffSearchParams(previous);
164	        return { ...rest, diff: "1" };
165	      },
166	    });
167	  }, [navigate, threadId]);
168	
169	  useEffect(() => {
170	    if (!threadsHydrated) {
171	      return;
172	    }
173	
174	    if (!routeThreadExists) {
175	      void navigate({ to: "/", replace: true });
176	      return;
177	    }
178	  }, [navigate, routeThreadExists, threadsHydrated, threadId]);
179	
180	  if (!threadsHydrated || !routeThreadExists) {
181	    return null;
182	  }
183	
184	  if (!shouldUseDiffSheet) {
185	    return (
186	      <>
187	        <SidebarInset className="h-dvh min-h-0 overflow-hidden overscroll-y-none bg-background text-foreground">
188	          <ChatView key={threadId} threadId={threadId} />
189	        </SidebarInset>
190	        <DiffPanelInlineSidebar diffOpen={diffOpen} onCloseDiff={closeDiff} onOpenDiff={openDiff} />
191	      </>
192	    );
193	  }
194	
195	  return (
196	    <>
197	      <SidebarInset className="h-dvh min-h-0 overflow-hidden overscroll-y-none bg-background text-foreground">
198	        <ChatView key={threadId} threadId={threadId} />
199	      </SidebarInset>
200	      <DiffPanelSheet diffOpen={diffOpen} onCloseDiff={closeDiff}>
201	        <Suspense fallback={<DiffLoadingFallback inline={false} />}>
202	          <DiffPanel mode="sheet" />
203	        </Suspense>
204	      </DiffPanelSheet>
205	    </>
206	  );
207	}
