1	import { Outlet, createFileRoute, useNavigate } from "@tanstack/react-router";
2	import { useEffect } from "react";
3	
4	import { DiffWorkerPoolProvider } from "../components/DiffWorkerPoolProvider";
5	import ThreadSidebar from "../components/Sidebar";
6	import { Sidebar, SidebarProvider } from "~/components/ui/sidebar";
7	
8	function ChatRouteLayout() {
9	  const navigate = useNavigate();
10	
11	  useEffect(() => {
12	    const onMenuAction = window.desktopBridge?.onMenuAction;
13	    if (typeof onMenuAction !== "function") {
14	      return;
15	    }
16	
17	    const unsubscribe = onMenuAction((action) => {
18	      if (action !== "open-settings") return;
19	      void navigate({ to: "/settings" });
20	    });
21	
22	    return () => {
23	      unsubscribe?.();
24	    };
25	  }, [navigate]);
26	
27	  return (
28	    <SidebarProvider defaultOpen>
29	      <Sidebar
30	        side="left"
31	        collapsible="offcanvas"
32	        className="border-r border-border bg-card text-foreground"
33	      >
34	        <ThreadSidebar />
35	      </Sidebar>
36	      <DiffWorkerPoolProvider>
37	        <Outlet />
38	      </DiffWorkerPoolProvider>
39	    </SidebarProvider>
40	  );
41	}
42	
43	export const Route = createFileRoute("/_chat")({
44	  component: ChatRouteLayout,
45	});
