import { useCallback, useEffect, useSyncExternalStore } from "react";
import { type Theme, DEFAULT_THEME_ID, getTheme, listThemes } from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:custom-theme";

let listeners: Array<() => void> = [];
let lastSnapshot: string | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getStoredId(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw && getTheme(raw)) return raw;
  return DEFAULT_THEME_ID;
}

function applyThemeToDom(theme: Theme) {
  const el = document.documentElement;

  // Toggle .dark class to keep the existing dark-mode CSS rules in sync
  el.classList.toggle("dark", theme.isDark);

  // Core semantic color variables
  el.style.setProperty("--background", theme.colors.background);
  el.style.setProperty("--foreground", theme.colors.foreground);
  el.style.setProperty("--card", theme.colors.sidebar);
  el.style.setProperty("--card-foreground", theme.colors.foreground);
  el.style.setProperty("--popover", theme.colors.sidebar);
  el.style.setProperty("--popover-foreground", theme.colors.foreground);
  el.style.setProperty("--primary", theme.colors.accent);
  el.style.setProperty("--ring", theme.colors.accent);

  // Editor / terminal / status-bar surfaces (new variables added in index.css)
  el.style.setProperty("--editor-background", theme.colors.editor);
  el.style.setProperty("--terminal-background", theme.colors.terminal);
  el.style.setProperty("--status-bar-background", theme.colors.statusBar);

  // Font family
  el.style.setProperty("--app-font-family", theme.fontFamily);
}

// Apply immediately on module load to prevent flash
applyThemeToDom(getTheme(getStoredId()) ?? getTheme(DEFAULT_THEME_ID)!);

function getSnapshot(): string {
  const id = getStoredId();
  if (lastSnapshot === id) return lastSnapshot;
  lastSnapshot = id;
  return id;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      const theme = getTheme(getStoredId());
      if (theme) applyThemeToDom(theme);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useCustomTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);
  const theme = getTheme(themeId) ?? (getTheme(DEFAULT_THEME_ID) as Theme);
  const availableThemes = listThemes();

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id);
    if (!next) return;
    localStorage.setItem(STORAGE_KEY, id);
    applyThemeToDom(next);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyThemeToDom(theme);
  }, [theme]);

  return { theme, setTheme, availableThemes } as const;
}

