import { useCustomTheme } from "~/hooks/useCustomTheme";

export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useCustomTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {availableThemes.map((t) => {
        const selected = t.id === theme.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => setTheme(t.id)}
            className={`flex w-full items-center justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
          >
            <span className="flex items-center gap-3">
              {/* Color swatches */}
              <span
                className="flex shrink-0 overflow-hidden rounded border border-border/50"
                aria-hidden="true"
              >
                <span
                  className="block size-4"
                  style={{ background: t.colors.background }}
                />
                <span
                  className="block size-4"
                  style={{ background: t.colors.accent }}
                />
                <span
                  className="block size-4"
                  style={{ background: t.colors.sidebar }}
                />
              </span>

              <span className="text-sm font-medium">{t.name}</span>
            </span>

            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

